 (颜色 . ((背景 "#FAFAFA") (标题 "#333") (副标题 "#555") (正文 "#333"))) 
 (尺寸 . ((卡片宽度 "auto") (卡片高度 "auto, >宽度") (内边距 "20px"))) 
 (布局 . (竖版 弹性布局 居中对齐)))) 
 - 卡片元素： 
